    if (!res.ok) {
      let msg = `HTTP ${res.status}`;
      try { const body = await res.json(); if (body.detail) msg = body.detail; } catch {}
      throw new Error(msg);
    }
    return res.json();
  }

  function fmtDate(iso) {
    if (!iso) return "—";
    try {
      const d = new Date(iso);
      if (isNaN(d)) return iso;
      return d.toISOString().replace("T", " ").slice(0, 16) + "Z";
    } catch { return iso; }
  }

  function toast(msg, kind) {
    const t = el("div", { class: `toast ${kind || ""}`, text: msg });
    document.body.appendChild(t);
    setTimeout(() => t.remove(), 6000);
    return t;
  }

  function toastWithCode(msg, code, kind) {
    const t = el("div", { class: `toast ${kind || ""}` }, [
      el("div", { text: msg }),
      el("code", { text: code }),
    ]);
    document.body.appendChild(t);
    setTimeout(() => t.remove(), 20000);
    return t;
  }

  // ── Renderers ──────────────────────────────────────────────────────────

  async function renderDashboard() {
    const root = qs("#dashboard-root");
    if (!root) return;
    root.innerHTML = "<div class='loading'>Loading stats…</div>";
    try {
      const s = await api("/admin/api/dashboard/stats");
      if (!s) return;
      const cards = [
        ["Total users", s.total_users],
        ["Live users", s.live_users],
        ["Banned", s.banned_users],
        ["Total likes", s.total_likes],
        ["Total matches", s.total_matches],
        ["Feedback: new", s.feedback_new],
        ["Feedback: resolved", s.feedback_resolved],
        ["Referrer credit total", s.referrer_value_total],
      ];
      root.innerHTML = "";
      const grid = el("div", { class: "stats-grid" });
      cards.forEach(([label, value]) => {
        grid.appendChild(el("div", { class: "stat-card" }, [
          el("div", { class: "label", text: label }),
          el("div", { class: "value", text: String(value) }),
        ]));
      });
      root.appendChild(grid);
    } catch (e) {
      root.innerHTML = `<div class='error'>Failed to load: ${e.message}</div>`;
    }
  }

  async function renderUsers() {
    const root = qs("#users-root");
    if (!root) return;
    const q = qs("#users-q")?.value || "";
    root.innerHTML = "<div class='loading'>Loading users…</div>";
    try {
      const data = await api(`/admin/api/users?q=${encodeURIComponent(q)}`);
      if (!data) return;
      root.innerHTML = "";
      const tbl = el("table", {}, [
        el("thead", {}, [el("tr", {}, [
          el("th", { text: "ID" }),
          el("th", { text: "Username" }),
          el("th", { text: "Age" }),
          el("th", { text: "Sex" }),
          el("th", { text: "Timezone" }),
          el("th", { text: "Speed" }),
          el("th", { text: "Created" }),
          el("th", { text: "Last login" }),
          el("th", { text: "Status" }),
          el("th", { text: "Actions" }),
        ])]),
      ]);
      const tbody = el("tbody");
      data.items.forEach(u => {
        const statusBadges = [];
        if (u.is_banned) statusBadges.push(el("span", { class: "badge badge-banned", text: "banned" }));
        if (u.deleted_at) statusBadges.push(el("span", { class: "badge badge-deleted", text: "deleted" }));
        tbody.appendChild(el("tr", {}, [
          el("td", { class: "num mono", text: String(u.id) }),
          el("td", { text: u.username || "—" }),
          el("td", { class: "num", text: u.age == null ? "—" : String(u.age) }),
          el("td", { class: "dim", text: u.sex || "—" }),
          el("td", { class: "dim", text: u.timezone || "—" }),
          el("td", { class: "dim", text: u.dating_speed || "—" }),
          el("td", { class: "dim mono", text: fmtDate(u.created_at) }),
          el("td", { class: "dim mono", text: fmtDate(u.last_login) }),
          el("td", {}, statusBadges),
          el("td", {}, [
            el("button", {
              text: u.is_banned ? "Unban" : "Ban",
              onclick: () => actUser("ban", u.id),
            }),
            " ",
            el("button", {
              class: "danger",
              text: "Delete",
              onclick: () => actUser("delete", u.id),
            }),
            " ",
            el("button", {
              text: "Reset pw",
              onclick: () => actUser("reset-password", u.id),
            }),
          ]),
        ]));
      });
      tbl.appendChild(tbody);
      root.appendChild(tbl);
      root.appendChild(el("div", { class: "dim", text: `${data.total} rows` }));
    } catch (e) {
      root.innerHTML = `<div class='error'>Failed to load: ${e.message}</div>`;
    }
  }

  async function actUser(action, userId) {
    const confirmMsg = {
      "ban": "Toggle ban on this user?",
      "delete": "Soft-delete this user? (Can be recovered by clearing deleted_at.)",
      "reset-password": "Generate a new random password? The current password becomes unusable immediately.",
    }[action];
    if (!confirm(confirmMsg)) return;
    try {
      const body = await api(`/admin/api/users/${userId}/${action}`, { method: "POST" });
      if (!body) return;
      if (action === "reset-password") {
        toastWithCode(
          `New password for ${body.username} (copy now):`,
          body.new_password,
          "success",
        );
      } else {
        toast(`OK: ${JSON.stringify(body)}`, "success");
      }
      if (action !== "reset-password") renderUsers();
    } catch (e) {
      toast(`Error: ${e.message}`, "error");
    }
  }

  async function renderFeedback() {
    const root = qs("#feedback-root");
    if (!root) return;
    root.innerHTML = "<div class='loading'>Loading feedback…</div>";
    try {
      const data = await api("/admin/api/feedback");
      if (!data) return;
      root.innerHTML = "";
      const tbl = el("table", {}, [
        el("thead", {}, [el("tr", {}, [
          el("th", { text: "ID" }),
          el("th", { text: "User" }),
          el("th", { text: "Description" }),
          el("th", { text: "App" }),
          el("th", { text: "Platform" }),
          el("th", { text: "Status" }),
          el("th", { text: "Created" }),
          el("th", { text: "Screenshot" }),
          el("th", { text: "Actions" }),
        ])]),
      ]);
      const tbody = el("tbody");
      data.items.forEach(f => {
        tbody.appendChild(el("tr", {}, [
          el("td", { class: "num mono", text: String(f.id) }),
          el("td", { text: f.username || `#${f.user_id || "?"}` }),
          el("td", { class: "feedback-desc", title: f.description, text: f.description }),
          el("td", { class: "dim mono", text: f.app_version || "—" }),
          el("td", { class: "dim", text: f.platform || "—" }),
          el("td", {}, [el("span", { class: `badge badge-${f.status}`, text: f.status })]),
          el("td", { class: "dim mono", text: fmtDate(f.created_at) }),
          el("td", {}, [
            f.screenshot_url
              ? el("a", { href: f.screenshot_url, target: "_blank", text: "view" })
              : document.createTextNode("—"),
          ]),
          el("td", {}, ["new", "read", "resolved"].filter(s => s !== f.status).map(s =>
            el("button", {
              text: s,
              onclick: () => setFeedbackStatus(f.id, s),
            })
          )),
        ]));
      });
      tbl.appendChild(tbody);
      root.appendChild(tbl);
    } catch (e) {
      root.innerHTML = `<div class='error'>Failed to load: ${e.message}</div>`;
    }
  }

  async function setFeedbackStatus(id, s) {
    try {
      const form = new FormData();
      form.append("status", s);
      const body = await api(`/admin/api/feedback/${id}/status`, {
        method: "POST",
        body: form,
      });
      if (!body) return;
      toast(`Feedback #${id} → ${s}`, "success");
      renderFeedback();
    } catch (e) {
      toast(`Error: ${e.message}`, "error");
    }
  }

  async function renderReferrals() {
    const root = qs("#referrals-root");
    if (!root) return;
    root.innerHTML = "<div class='loading'>Loading referrals…</div>";
    try {
      const data = await api("/admin/api/referrals");
      if (!data) return;
      root.innerHTML = "";
      const tbl = el("table", {}, [
        el("thead", {}, [el("tr", {}, [
          el("th", { text: "ID" }),
          el("th", { text: "Referrer" }),
          el("th", { text: "Referred" }),
          el("th", { text: "Event" }),
          el("th", { text: "Value" }),
          el("th", { text: "Created" }),
        ])]),
      ]);
      const tbody = el("tbody");
      data.items.forEach(r => {
        tbody.appendChild(el("tr", {}, [
          el("td", { class: "num mono", text: String(r.id) }),
          el("td", { text: r.referrer_username || "—" }),
          el("td", { text: r.referred_username || "—" }),
          el("td", { class: "dim mono", text: r.event_name }),
          el("td", { class: "num", text: String(r.value) }),
          el("td", { class: "dim mono", text: fmtDate(r.created_at) }),
        ]));
      });
      tbl.appendChild(tbody);
      root.appendChild(tbl);
    } catch (e) {
      root.innerHTML = `<div class='error'>Failed to load: ${e.message}</div>`;
    }
  }

  async function renderLikes() {
    const root = qs("#likes-root");
    if (!root) return;
    root.innerHTML = "<div class='loading'>Loading likes…</div>";
    try {
      const data = await api("/admin/api/likes?per_page=200");
      if (!data) return;
      root.innerHTML = "";
      const tbl = el("table", {}, [
        el("thead", {}, [el("tr", {}, [
          el("th", { text: "ID" }),
          el("th", { text: "Liker" }),
          el("th", { text: "Liked" }),
          el("th", { text: "Voice note" }),
        ])]),
      ]);
      const tbody = el("tbody");
      data.items.forEach(l => {
        tbody.appendChild(el("tr", {}, [
          el("td", { class: "num mono", text: String(l.id) }),
          el("td", { text: `${l.liker_username || "?"} (${l.liker_id})` }),
          el("td", { text: `${l.liked_username || "?"} (${l.liked_id})` }),
          el("td", { class: "dim mono", text: l.voice_note || "—" }),
        ]));
      });
      tbl.appendChild(tbody);
      root.appendChild(tbl);
      root.appendChild(el("div", { class: "dim", text: `${data.total} total` }));
    } catch (e) {
      root.innerHTML = `<div class='error'>Failed to load: ${e.message}</div>`;
    }
  }

  async function renderMatches() {
    const root = qs("#matches-root");
    if (!root) return;
    root.innerHTML = "<div class='loading'>Loading matches…</div>";
    try {
      const data = await api("/admin/api/matches?per_page=200");
      if (!data) return;
      root.innerHTML = "";
      const tbl = el("table", {}, [
        el("thead", {}, [el("tr", {}, [
          el("th", { text: "ID" }),
          el("th", { text: "User 1" }),
          el("th", { text: "User 2" }),
          el("th", { text: "Created" }),
        ])]),
      ]);
      const tbody = el("tbody");
      data.items.forEach(m => {
        tbody.appendChild(el("tr", {}, [
          el("td", { class: "num mono", text: String(m.id) }),
          el("td", { text: `${m.user1_username || "?"} (${m.user1_id})` }),
          el("td", { text: `${m.user2_username || "?"} (${m.user2_id})` }),
          el("td", { class: "dim mono", text: fmtDate(m.created_at) }),
        ]));
      });
      tbl.appendChild(tbody);
      root.appendChild(tbl);
      root.appendChild(el("div", { class: "dim", text: `${data.total} total` }));
    } catch (e) {
      root.innerHTML = `<div class='error'>Failed to load: ${e.message}</div>`;
    }
  }

  window.AdminPanel = {
    renderDashboard,
    renderUsers,
    renderFeedback,
    renderReferrals,
    renderLikes,
    renderMatches,
  };
})();

