/* Admin panel dark theme — small, utilitarian, no framework */

:root {
  --bg: #0f1115;
  --bg-elev: #161a21;
  --bg-elev-2: #1d222c;
  --border: #262c38;
  --text: #e6e8ee;
  --text-dim: #8a91a0;
  --accent: #4f8cff;
  --accent-hover: #6a9eff;
  --danger: #ef4444;
  --danger-hover: #f87171;
  --success: #22c55e;
  --warning: #f59e0b;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  font-size: 14px;
  line-height: 1.45;
}

a { color: var(--accent); text-decoration: none; }
a:hover { color: var(--accent-hover); }

nav.topbar {
  display: flex;
  align-items: center;
  gap: .25rem;
  padding: .5rem 1rem;
  background: var(--bg-elev);
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 0;
  z-index: 10;
}

nav.topbar .brand {
  font-weight: 600;
  margin-right: 1rem;
  color: var(--text);
}

nav.topbar a {
  padding: .4rem .8rem;
  border-radius: 6px;
  color: var(--text-dim);
}

nav.topbar a.active {
  background: var(--bg-elev-2);
  color: var(--text);
}

nav.topbar a:hover {
  background: var(--bg-elev-2);
  color: var(--text);
}

nav.topbar .spacer { flex: 1; }

main.container {
  padding: 1.5rem;
  max-width: 1400px;
  margin: 0 auto;
}

h1 {
  font-size: 1.4rem;
  font-weight: 600;
  margin: 0 0 1rem 0;
}

h2 {
  font-size: 1.1rem;
  font-weight: 600;
  margin: 1.5rem 0 .75rem 0;
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: .75rem;
  margin-bottom: 1.5rem;
}

.stat-card {
  background: var(--bg-elev);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1rem;
}

.stat-card .label {
  color: var(--text-dim);
  font-size: .75rem;
  text-transform: uppercase;
  letter-spacing: .05em;
}

.stat-card .value {
  font-size: 1.75rem;
  font-weight: 600;
