/* Admin panel auth helper — JWT in sessionStorage + authFetch wrapper.
   Pairs with M53 backend change: /admin/api/* now requires Authorization:
   Bearer <jwt> where the JWT subject is in ADMIN_USERNAMES. */

(function () {
  "use strict";

  const TOKEN_KEY = "admin_jwt";
  const LOGIN_URL = "/admin/login.html";

  function getToken() {
    return sessionStorage.getItem(TOKEN_KEY);
  }

  function setToken(t) {
    sessionStorage.setItem(TOKEN_KEY, t);
  }

  function clearToken() {
    sessionStorage.removeItem(TOKEN_KEY);
  }

  // Redirect to login if no token. Returns true if authed, false if redirecting.
  // Pages call this on DOMContentLoaded before their first fetch so we don't
  // render a loading spinner that's about to bounce.
  function requireAuth() {
    if (!getToken()) {
      window.location.href = LOGIN_URL;
      return false;
    }
    return true;
  }

  // fetch() wrapper that (1) attaches Authorization: Bearer,
  // (2) on 401 clears token + redirects to login (token likely expired),
  // (3) on 403 clears token + redirects to login?err=not_admin (account
  //     is authenticated but NOT in ADMIN_USERNAMES — a non-admin JWT is
  //     useless for the panel, so evict it).
  async function authFetch(url, opts) {
    opts = opts || {};
    const token = getToken();
    const headers = new Headers(opts.headers || {});
    if (token) headers.set("Authorization", "Bearer " + token);
    const res = await fetch(url, Object.assign({}, opts, { headers }));
    if (res.status === 401) {
      clearToken();
      window.location.href = LOGIN_URL;
      return null;
    }
    if (res.status === 403) {
      clearToken();
      window.location.href = LOGIN_URL + "?err=not_admin";
      return null;
    }
    return res;
  }

  function logout() {
    clearToken();
    window.location.href = LOGIN_URL;
  }

  window.AdminAuth = {
    getToken,
    setToken,
    clearToken,
    requireAuth,
    authFetch,
    logout,
  };
})();

