async function api(path, opts) {
  opts = opts || {};
  const res = await fetch(path, {
    credentials: "same-origin",
    ...opts,
  });
  if (res.status === 401) {
    window.location.href = "/admin/login";
    return null;
  }
  if (!res.ok) {
    let msg = `HTTP ${res.status}`;
    try { const body = await res.json(); if (body.detail) msg = body.detail; } catch {}
    throw new Error(msg);
  }
  return res.json();
}

