def _validate_month(month: Optional[str]) -> str:
    """Return a YYYY-MM string; default to current UTC month. 400 on bad input."""
    if month is None:
        return datetime.utcnow().strftime("%Y-%m")
    try:
        datetime.strptime(month, "%Y-%m")
    except ValueError:
        raise HTTPException(status_code=400, detail="month must be YYYY-MM")
    return month


@router.get("/api/referrals/payout-summary/months")
async def api_referral_payout_months(
    _=Depends(require_admin_panel_user),
    db: Session = Depends(get_db),
):
    """All YYYY-MM buckets that have at least one referrer_event. Descending
    (newest first) for dropdown UX."""
    rows = (
        db.query(func.strftime("%Y-%m", ReferrerEvent.created_at).label("month"))
        .group_by("month")
        .order_by(func.strftime("%Y-%m", ReferrerEvent.created_at).desc())
        .all()
    )
    return {"months": [r.month for r in rows if r.month]}


@router.get("/api/referrals/payout-summary")
async def api_referral_payout_summary(
    month: Optional[str] = None,
    _=Depends(require_admin_panel_user),
    db: Session = Depends(get_db),
):
    """Per-referrer aggregation for a single month. Used for payout processing."""
    month = _validate_month(month)
    rows = (
        db.query(
            ReferrerEvent.referrer_username,
            func.sum(ReferrerEvent.value).label("total_value"),
            func.count(ReferrerEvent.id).label("event_count"),
            func.count(func.distinct(ReferrerEvent.referred_username)).label("unique_referred"),
        )
        .filter(func.strftime("%Y-%m", ReferrerEvent.created_at) == month)
        .group_by(ReferrerEvent.referrer_username)
        .order_by(func.sum(ReferrerEvent.value).desc())
        .all()
    )
    items = [
        {
            "referrer_username": r.referrer_username,
            "total_value": int(r.total_value or 0),
            "event_count": int(r.event_count or 0),
            "unique_referred": int(r.unique_referred or 0),
        }
        for r in rows
    ]
    return {
        "month": month,
        "items": items,
        "grand_total": sum(it["total_value"] for it in items),
        "referrer_count": len(items),
    }


@router.get("/api/referrals/{username}/events")
async def api_referral_user_events(
    username: str,
    month: Optional[str] = None,
    _=Depends(require_admin_panel_user),
    db: Session = Depends(get_db),
):
    """Drill-down: every referrer_event for a given referrer in the given month,
    chronological."""
    month = _validate_month(month)
    rows = (
        db.query(ReferrerEvent)
        .filter(
            ReferrerEvent.referrer_username == username,
            func.strftime("%Y-%m", ReferrerEvent.created_at) == month,
        )
        .order_by(ReferrerEvent.created_at.asc())
        .all()
    )
    items = [
        {
            "id": r.id,
            "event_name": r.event_name,
            "value": r.value,
            "referred_username": r.referred_username,
            "created_at": r.created_at.isoformat() + "Z" if r.created_at else None,
        }
        for r in rows
    ]
    return {
        "referrer_username": username,
        "month": month,
        "items": items,
        "total_value": sum(it["value"] for it in items),
        "event_count": len(items),
    }


