        `/admin/api/referrals/${encodeURIComponent(username)}/events?month=${encodeURIComponent(month)}`
      );
      if (!data) return;
      det.innerHTML = "";
      const card = el("div", { class: "detail-card" });
      card.appendChild(el("h2", {
        text: `${username} — ${month} — ${data.event_count} events, total ${data.total_value}`,
      }));
      const tbl = el("table", {}, [
        el("thead", {}, [el("tr", {}, [
          el("th", { text: "ID" }),
          el("th", { text: "Event" }),
          el("th", { text: "Value" }),
          el("th", { text: "Referred user" }),
          el("th", { text: "Created" }),
        ])]),
      ]);
      const tbody = el("tbody");
      (data.items || []).forEach(it => {
        tbody.appendChild(el("tr", {}, [
          el("td", { class: "num mono", text: String(it.id) }),
          el("td", { class: "dim mono", text: it.event_name }),
          el("td", { class: "num mono", text: String(it.value) }),
          el("td", { text: it.referred_username }),
          el("td", { class: "dim mono", text: fmtDate(it.created_at) }),
        ]));
      });
      tbl.appendChild(tbody);
      card.appendChild(tbl);
      card.appendChild(el("button", {
        text: "Close",
        onclick: () => { det.innerHTML = ""; },
      }));
      det.appendChild(card);
      card.scrollIntoView({ behavior: "smooth", block: "start" });
    } catch (e) {
      det.innerHTML = `<div class='error'>Failed to load details: ${e.message}</div>`;
    }
  }

  async function exportPayoutsCSV() {
    const month = qs("#payouts-month")?.value;
    if (!month) return;
    try {
      const data = await api(`/admin/api/referrals/payout-summary?month=${encodeURIComponent(month)}`);
      if (!data) return;
      const header = ["referrer_username", "total_value", "event_count", "unique_referred"];
      const rows = [header, ...data.items.map(r => [
        r.referrer_username, r.total_value, r.event_count, r.unique_referred,
      ])];
      const csv = rows.map(row => row.map(cell => {
        const s = cell == null ? "" : String(cell);
        // RFC 4180: quote when value contains comma, quote, CR, or LF;
        // escape embedded quotes by doubling them.
        if (/[",\n\r]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
        return s;
      }).join(",")).join("\n");
      const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
      const url = URL.createObjectURL(blob);
      const a = el("a", {
        href: url,
        download: `referral_payouts_${month.replace("-", "_")}.csv`,
      });
      document.body.appendChild(a);
      a.click();
      setTimeout(() => { a.remove(); URL.revokeObjectURL(url); }, 100);
    } catch (e) {
      toast(`CSV export failed: ${e.message}`, "error");
    }
  }

  window.AdminPanel = {
    renderDashboard,
    renderUsers,
    renderFeedback,
    renderReferrals,
    renderLikes,
    renderMatches,
    initPayouts,
    renderPayouts,
    renderPayoutDetails,
    exportPayoutsCSV,
  };
})();

