/* Admin panel dark theme — small, utilitarian, no framework */

:root {
  --bg: #0f1115;
  --bg-elev: #161a21;
  --bg-elev-2: #1d222c;
  --border: #262c38;
  --text: #e6e8ee;
  --text-dim: #8a91a0;
  --accent: #4f8cff;
  --accent-hover: #6a9eff;
  --danger: #ef4444;
  --danger-hover: #f87171;
  --success: #22c55e;
  --warning: #f59e0b;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  font-size: 14px;
  line-height: 1.45;
}

a { color: var(--accent); text-decoration: none; }
a:hover { color: var(--accent-hover); }

nav.topbar {
  display: flex;
  align-items: center;
  gap: .25rem;
  padding: .5rem 1rem;
  background: var(--bg-elev);
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 0;
  z-index: 10;
}

nav.topbar .brand {
  font-weight: 600;
  margin-right: 1rem;
  color: var(--text);
}

nav.topbar a {
  padding: .4rem .8rem;
  border-radius: 6px;
  color: var(--text-dim);
}

nav.topbar a.active {
  background: var(--bg-elev-2);
  color: var(--text);
}

nav.topbar a:hover {
  background: var(--bg-elev-2);
  color: var(--text);
}

nav.topbar .spacer { flex: 1; }

main.container {
  padding: 1.5rem;
  max-width: 1400px;
  margin: 0 auto;
}

h1 {
  font-size: 1.4rem;
  font-weight: 600;
  margin: 0 0 1rem 0;
}

h2 {
  font-size: 1.1rem;
  font-weight: 600;
  margin: 1.5rem 0 .75rem 0;
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: .75rem;
  margin-bottom: 1.5rem;
}

.stat-card {
  background: var(--bg-elev);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1rem;
}

.stat-card .label {
  color: var(--text-dim);
  font-size: .75rem;
  text-transform: uppercase;
  letter-spacing: .05em;
}

.stat-card .value {
  font-size: 1.75rem;
  font-weight: 600;
  margin-top: .25rem;
}

table {
  width: 100%;
  border-collapse: collapse;
  background: var(--bg-elev);
  border: 1px solid var(--border);
  border-radius: 8px;
  overflow: hidden;
}

th, td {
  text-align: left;
  padding: .6rem .75rem;
  border-bottom: 1px solid var(--border);
  font-size: .85rem;
}

th {
  background: var(--bg-elev-2);
  color: var(--text-dim);
  font-weight: 500;
  text-transform: uppercase;
  font-size: .7rem;
  letter-spacing: .05em;
}

tr:last-child td { border-bottom: none; }
tr:hover td { background: var(--bg-elev-2); }

td.num { text-align: right; font-variant-numeric: tabular-nums; }
td.mono { font-family: "SF Mono", ui-monospace, monospace; }
td.dim { color: var(--text-dim); }

.badge {
  display: inline-block;
  padding: .15rem .5rem;
  border-radius: 4px;
  font-size: .7rem;
  font-weight: 500;
  text-transform: uppercase;
}

.badge-new { background: #1e3a8a; color: #bfdbfe; }
.badge-read { background: #78350f; color: #fde68a; }
.badge-resolved { background: #14532d; color: #bbf7d0; }
.badge-banned { background: #7f1d1d; color: #fecaca; }
.badge-deleted { background: #374151; color: #9ca3af; }

button, .button {
  background: var(--bg-elev-2);
  border: 1px solid var(--border);
  color: var(--text);
  padding: .35rem .7rem;
  border-radius: 5px;
  font-size: .8rem;
  cursor: pointer;
  font-family: inherit;
}

button:hover, .button:hover {
  background: var(--border);
}

button.danger { background: #7f1d1d; border-color: #991b1b; color: #fecaca; }
button.danger:hover { background: var(--danger); color: #fff; }

button.primary { background: var(--accent); border-color: var(--accent); color: #fff; }
button.primary:hover { background: var(--accent-hover); border-color: var(--accent-hover); }

input[type="text"], input[type="password"], input[type="search"], select {
  background: var(--bg-elev-2);
  border: 1px solid var(--border);
  color: var(--text);
  padding: .4rem .6rem;
  border-radius: 5px;
  font-size: .85rem;
  font-family: inherit;
}

input:focus, select:focus { outline: 2px solid var(--accent); outline-offset: 0; }

.toolbar {
  display: flex;
  gap: .5rem;
  align-items: center;
  margin-bottom: 1rem;
}

.toolbar .spacer { flex: 1; }

.loading { color: var(--text-dim); padding: 1rem; }
.error { color: var(--danger); padding: 1rem; background: #2a0f0f; border-radius: 6px; border: 1px solid #5c1f1f; }

/* login page */
.login-wrap {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
}

.login-card {
  background: var(--bg-elev);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 2rem;
  width: 100%;
  max-width: 340px;
}

.login-card h1 { margin: 0 0 .25rem 0; font-size: 1.3rem; }
.login-card p { color: var(--text-dim); margin: 0 0 1.5rem 0; font-size: .85rem; }
.login-card input { width: 100%; margin-bottom: .75rem; }
.login-card button { width: 100%; padding: .6rem; }

.feedback-desc {
  max-width: 500px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* modal / toast for reset password plaintext */
.toast {
  position: fixed;
  top: 1rem;
  right: 1rem;
  background: var(--bg-elev);
  border: 1px solid var(--border);
  padding: .75rem 1rem;
  border-radius: 6px;
  max-width: 400px;
  box-shadow: 0 10px 20px rgba(0,0,0,.4);
  z-index: 100;
}

.toast.success { border-color: var(--success); }
.toast.error { border-color: var(--danger); }

.toast code {
  display: block;
  margin-top: .5rem;
  padding: .5rem;
  background: var(--bg);
  border-radius: 4px;
  font-family: "SF Mono", ui-monospace, monospace;
  font-size: .85rem;
  user-select: all;
}

