/* Admin panel theme — dark by default, light via [data-theme="light"] on <html>.
   All colors are CSS custom properties so themes can override in one place.
   Page HTML sets data-theme from localStorage('admin_theme') in an inline head
   script BEFORE this stylesheet is parsed, to avoid a flash of the wrong mode. */

:root {
  /* Surfaces */
  --bg: #0f1115;
  --bg-elev: #161a21;
  --bg-elev-2: #1d222c;

  /* Text + borders */
  --border: #262c38;
  --text: #e6e8ee;
  --text-dim: #8a91a0;

  /* Brand */
  --accent: #4f8cff;
  --accent-hover: #6a9eff;
  --danger: #ef4444;
  --danger-hover: #f87171;
  --success: #22c55e;
  --warning: #f59e0b;

  /* Button states */
  --btn-primary-fg: #ffffff;
  --btn-danger-bg: #7f1d1d;
  --btn-danger-border: #991b1b;
  --btn-danger-fg: #fecaca;
  --btn-danger-hover-fg: #ffffff;

  /* Status badges */
  --badge-new-bg: #1e3a8a;      --badge-new-fg: #bfdbfe;
  --badge-read-bg: #78350f;     --badge-read-fg: #fde68a;
  --badge-resolved-bg: #14532d; --badge-resolved-fg: #bbf7d0;
  --badge-banned-bg: #7f1d1d;   --badge-banned-fg: #fecaca;
  --badge-deleted-bg: #374151;  --badge-deleted-fg: #9ca3af;

  /* Error block */
  --error-bg: #2a0f0f;
  --error-border: #5c1f1f;

  /* Effects */
  --toast-shadow: 0 10px 20px rgba(0, 0, 0, 0.4);
}

[data-theme="light"] {
  /* Surfaces */
  --bg: #f6f7fa;
  --bg-elev: #ffffff;
  --bg-elev-2: #eef1f5;

  /* Text + borders */
  --border: #dfe3ea;
  --text: #1a1d23;
  --text-dim: #6b7280;

  /* Brand — a touch more saturated to hold contrast on white */
  --accent: #2563eb;
  --accent-hover: #1d4ed8;
  --danger: #dc2626;
  --danger-hover: #b91c1c;
  --success: #16a34a;
  --warning: #d97706;

  /* Button states — pale danger bg, dark fg in light mode */
  --btn-primary-fg: #ffffff;
  --btn-danger-bg: #fee2e2;
  --btn-danger-border: #fecaca;
  --btn-danger-fg: #991b1b;
  --btn-danger-hover-fg: #ffffff;

  /* Status badges — pale bg, dark fg reads cleanly on light surfaces */
  --badge-new-bg: #dbeafe;      --badge-new-fg: #1e40af;
  --badge-read-bg: #fef3c7;     --badge-read-fg: #92400e;
  --badge-resolved-bg: #dcfce7; --badge-resolved-fg: #166534;
  --badge-banned-bg: #fee2e2;   --badge-banned-fg: #991b1b;
  --badge-deleted-bg: #e5e7eb;  --badge-deleted-fg: #374151;

  /* Error block */
  --error-bg: #fef2f2;
  --error-border: #fecaca;

  /* Effects — much softer shadow on a white surface */
  --toast-shadow: 0 8px 20px rgba(15, 23, 42, 0.10);
}

* { box-sizing: border-box; }

html, body {
