(function () {
  "use strict";

  // ── Theme (light/dark) ────────────────────────────────────────────────
  // Pairs with the inline <head> script on each page that applies
  // data-theme BEFORE the stylesheet is parsed. This module handles
  // runtime toggling + icon sync. Persisted as localStorage.admin_theme.
  const THEME_KEY = "admin_theme";

  function currentTheme() {
    return document.documentElement.getAttribute("data-theme") === "light"
      ? "light" : "dark";
  }

  function applyTheme(t) {
    const v = t === "light" ? "light" : "dark";
    document.documentElement.setAttribute("data-theme", v);
    try { localStorage.setItem(THEME_KEY, v); } catch (e) {}
    updateThemeIcon();
  }

  function toggleTheme() {
    applyTheme(currentTheme() === "light" ? "dark" : "light");
  }

  function updateThemeIcon() {
    const btn = document.getElementById("theme-toggle");
    if (!btn) return;
    // Show the icon representing the mode you would switch TO.
    const inLight = currentTheme() === "light";
    btn.textContent = inLight ? "☾" : "☀";
    btn.title = inLight ? "Switch to dark mode" : "Switch to light mode";
    btn.setAttribute("aria-label", btn.title);
  }

  // Every page imports this module, so auto-init the theme icon once the
  // DOM is ready. Idempotent and no-op when no #theme-toggle exists
  // (e.g. login page).
  document.addEventListener("DOMContentLoaded", updateThemeIcon);

  window.AdminTheme = {
    current: currentTheme,
    apply: applyTheme,
    toggle: toggleTheme,
    update: updateThemeIcon,
  };

  function qs(sel, root) { return (root || document).querySelector(sel); }

