22	    document.addEventListener("DOMContentLoaded", () => {
23	      const errEl = document.getElementById("err");
24	
25	      // Surface a "not an admin" message when authFetch bounces us here
26	      // with ?err=not_admin. The user's JWT was valid but lacked admin
27	      // role — token was already cleared in authFetch.
28	      const qs = new URLSearchParams(location.search);
29	      if (qs.get("err") === "not_admin") {
