def _body_photo_url_map(db: Session, user_ids):
    """Map user_id → /api/users/<id>/body_photo URL for users in `user_ids`
    who have a full_length gallery slot. Users without one are absent from
    the map, so .get(id) returns None."""
    if not user_ids:
        return {}
    rows = (
        db.query(UserMedia.user_id)
        .filter(UserMedia.user_id.in_(user_ids), UserMedia.slot == "full_length")
        .all()
    )
    return {
        r[0]: f"{config.BASE_URL}/photos/gallery_{r[0]}_full_length.jpg"
        for r in rows
    }

# Optional auth bearer (does not raise if missing/invalid)
_optional_bearer = HTTPBearer(auto_error=False)

async def get_optional_current_user(
    credentials: Optional[HTTPAuthorizationCredentials] = Depends(_optional_bearer),
    db: Session = Depends(get_db),
) -> Optional[User]:
    """Return the current user if a valid token is provided, else None."""
    if credentials is None:
        return None
    try:
        payload = jwt.decode(credentials.credentials, SECRET_KEY, algorithms=[ALGORITHM])
        username: str = payload.get("sub")
        if username is None:
            return None
        return db.query(User).filter(User.username == username).first()
    except JWTError:
        return None


