_APPROVED_FOR_PUBLIC = ("approved", "auto_approved")


def _body_photo_url_map(db: Session, user_ids):
    """Map user_id → /api/users/<id>/body_photo URL for users in `user_ids`
    who have a full_length gallery slot that is approved (or auto_approved
    — the backfill state for pre-moderation rows). Users whose full_length
    is pending/rejected are absent from the map, so .get(id) returns None
    and public list endpoints emit body_photo_url=None.
    Self-view endpoints build photo URLs directly (not via this map) and
    are intentionally NOT filtered — users see their own pending photos."""
    if not user_ids:
        return {}
    rows = (
        db.query(UserMedia.user_id)
        .filter(
            UserMedia.user_id.in_(user_ids),
            UserMedia.slot == "full_length",
            UserMedia.moderation_status.in_(_APPROVED_FOR_PUBLIC),
        )
        .all()
    )
    return {
        r[0]: f"{config.BASE_URL}/photos/gallery_{r[0]}_full_length.jpg"
        for r in rows
    }


def _face_photo_url_map(db: Session, user_ids):
    """Map user_id → face-photo URL for users whose face photo is approved
    or auto_approved. A user's face comes from EITHER user_photos (legacy
    profile row, stamped photoface_<id>.jpg) OR user_media slot='face'
    (gallery upload writes a mirror copy into PHOTOS_DIR). Either source
    being approved is enough to surface the URL — a user sees the profile.
    Users with only pending/rejected face rows are absent from the map."""
    if not user_ids:
        return {}
    result = {}
    for uid, in (
        db.query(UserPhoto.user_id)
        .filter(
            UserPhoto.user_id.in_(user_ids),
            UserPhoto.photo_filename.isnot(None),
            UserPhoto.moderation_status.in_(_APPROVED_FOR_PUBLIC),
        )
        .all()
    ):
        result[uid] = f"{config.BASE_URL}/photos/photoface_{uid}.jpg"
    for uid, in (
        db.query(UserMedia.user_id)
        .filter(
            UserMedia.user_id.in_(user_ids),
            UserMedia.slot == "face",
            UserMedia.moderation_status.in_(_APPROVED_FOR_PUBLIC),
        )
        .all()
    ):
        result.setdefault(uid, f"{config.BASE_URL}/photos/photoface_{uid}.jpg")
    return result

