/* Admin panel theme — dark by default, light via [data-theme="light"] on <html>.
   All colors are CSS custom properties so themes can override in one place.
   Page HTML sets data-theme from localStorage('admin_theme') in an inline head
   script BEFORE this stylesheet is parsed, to avoid a flash of the wrong mode. */

:root {
  /* Surfaces */
  --bg: #0f1115;
  --bg-elev: #161a21;
  --bg-elev-2: #1d222c;

  /* Text + borders */
  --border: #262c38;
  --text: #e6e8ee;
  --text-dim: #8a91a0;

  /* Brand */
  --accent: #4f8cff;
  --accent-hover: #6a9eff;
  --danger: #ef4444;
  --danger-hover: #f87171;
  --success: #22c55e;
  --warning: #f59e0b;

  /* Button states */
  --btn-primary-fg: #ffffff;
  --btn-danger-bg: #7f1d1d;
  --btn-danger-border: #991b1b;
  --btn-danger-fg: #fecaca;
  --btn-danger-hover-fg: #ffffff;

  /* Status badges */
  --badge-new-bg: #1e3a8a;      --badge-new-fg: #bfdbfe;
  --badge-read-bg: #78350f;     --badge-read-fg: #fde68a;
  --badge-resolved-bg: #14532d; --badge-resolved-fg: #bbf7d0;
  --badge-banned-bg: #7f1d1d;   --badge-banned-fg: #fecaca;
  --badge-deleted-bg: #374151;  --badge-deleted-fg: #9ca3af;

  /* Error block */
  --error-bg: #2a0f0f;
  --error-border: #5c1f1f;

  /* Effects */
  --toast-shadow: 0 10px 20px rgba(0, 0, 0, 0.4);
}

[data-theme="light"] {
  /* Surfaces */
  --bg: #f6f7fa;
  --bg-elev: #ffffff;
  --bg-elev-2: #eef1f5;

  /* Text + borders */
  --border: #dfe3ea;
  --text: #1a1d23;
  --text-dim: #6b7280;

  /* Brand — a touch more saturated to hold contrast on white */
  --accent: #2563eb;
  --accent-hover: #1d4ed8;
  --danger: #dc2626;
  --danger-hover: #b91c1c;
  --success: #16a34a;
  --warning: #d97706;

  /* Button states — pale danger bg, dark fg in light mode */
  --btn-primary-fg: #ffffff;
  --btn-danger-bg: #fee2e2;
  --btn-danger-border: #fecaca;
  --btn-danger-fg: #991b1b;
  --btn-danger-hover-fg: #ffffff;

  /* Status badges — pale bg, dark fg reads cleanly on light surfaces */
  --badge-new-bg: #dbeafe;      --badge-new-fg: #1e40af;
  --badge-read-bg: #fef3c7;     --badge-read-fg: #92400e;
  --badge-resolved-bg: #dcfce7; --badge-resolved-fg: #166534;
  --badge-banned-bg: #fee2e2;   --badge-banned-fg: #991b1b;
  --badge-deleted-bg: #e5e7eb;  --badge-deleted-fg: #374151;

  /* Error block */
  --error-bg: #fef2f2;
  --error-border: #fecaca;

  /* Effects — much softer shadow on a white surface */
  --toast-shadow: 0 8px 20px rgba(15, 23, 42, 0.10);
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  font-size: 14px;
  line-height: 1.45;
  transition: background 0.2s ease, color 0.2s ease;
}

a { color: var(--accent); text-decoration: none; }
a:hover { color: var(--accent-hover); }

nav.topbar {
  display: flex;
  align-items: center;
  gap: .25rem;
  padding: .5rem 1rem;
  background: var(--bg-elev);
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 0;
  z-index: 10;
  transition: background 0.2s ease, border-color 0.2s ease;
}

nav.topbar .brand {
  font-weight: 600;
  margin-right: 1rem;
  color: var(--text);
}

nav.topbar a {
  padding: .4rem .8rem;
  border-radius: 6px;
  color: var(--text-dim);
}

nav.topbar a.active {
  background: var(--bg-elev-2);
  color: var(--text);
}

nav.topbar a:hover {
  background: var(--bg-elev-2);
  color: var(--text);
}

nav.topbar .spacer { flex: 1; }

nav.topbar #theme-toggle {
  font-size: 1.05rem;
  line-height: 1;
  padding: .35rem .6rem;
  user-select: none;
}

main.container {
  padding: 1.5rem;
  max-width: 1400px;
  margin: 0 auto;
}

h1 {
  font-size: 1.4rem;
  font-weight: 600;
  margin: 0 0 1rem 0;
}

h2 {
  font-size: 1.1rem;
  font-weight: 600;
  margin: 1.5rem 0 .75rem 0;
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: .75rem;
  margin-bottom: 1.5rem;
}

.stat-card {
  background: var(--bg-elev);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1rem;
  transition: background 0.2s ease, border-color 0.2s ease;
}

.stat-card .label {
  color: var(--text-dim);
  font-size: .75rem;
  text-transform: uppercase;
  letter-spacing: .05em;
}

.stat-card .value {
  font-size: 1.75rem;
  font-weight: 600;
  margin-top: .25rem;
}

table {
  width: 100%;
  border-collapse: collapse;
  background: var(--bg-elev);
  border: 1px solid var(--border);
  border-radius: 8px;
  overflow: hidden;
  transition: background 0.2s ease, border-color 0.2s ease;
}

th, td {
  text-align: left;
  padding: .6rem .75rem;
  border-bottom: 1px solid var(--border);
  font-size: .85rem;
}

th {
  background: var(--bg-elev-2);
  color: var(--text-dim);
  font-weight: 500;
  text-transform: uppercase;
  font-size: .7rem;
  letter-spacing: .05em;
}

tr:last-child td { border-bottom: none; }
tr:hover td { background: var(--bg-elev-2); }

td.num { text-align: right; font-variant-numeric: tabular-nums; }
td.mono { font-family: "SF Mono", ui-monospace, monospace; }
td.dim { color: var(--text-dim); }

.badge {
  display: inline-block;
  padding: .15rem .5rem;
  border-radius: 4px;
  font-size: .7rem;
  font-weight: 500;
  text-transform: uppercase;
}

.badge-new      { background: var(--badge-new-bg);      color: var(--badge-new-fg); }
.badge-read     { background: var(--badge-read-bg);     color: var(--badge-read-fg); }
.badge-resolved { background: var(--badge-resolved-bg); color: var(--badge-resolved-fg); }
.badge-banned   { background: var(--badge-banned-bg);   color: var(--badge-banned-fg); }
.badge-deleted  { background: var(--badge-deleted-bg);  color: var(--badge-deleted-fg); }

button, .button {
  background: var(--bg-elev-2);
  border: 1px solid var(--border);
  color: var(--text);
  padding: .35rem .7rem;
  border-radius: 5px;
  font-size: .8rem;
  cursor: pointer;
  font-family: inherit;
}

button:hover, .button:hover {
  background: var(--border);
}

button.danger {
  background: var(--btn-danger-bg);
  border-color: var(--btn-danger-border);
  color: var(--btn-danger-fg);
}
button.danger:hover {
  background: var(--danger);
  color: var(--btn-danger-hover-fg);
  border-color: var(--danger);
}

button.primary {
  background: var(--accent);
  border-color: var(--accent);
  color: var(--btn-primary-fg);
}
button.primary:hover {
  background: var(--accent-hover);
  border-color: var(--accent-hover);
}

input[type="text"], input[type="password"], input[type="search"], select {
  background: var(--bg-elev-2);
  border: 1px solid var(--border);
  color: var(--text);
  padding: .4rem .6rem;
  border-radius: 5px;
  font-size: .85rem;
  font-family: inherit;
}

input:focus, select:focus { outline: 2px solid var(--accent); outline-offset: 0; }

.toolbar {
  display: flex;
  gap: .5rem;
  align-items: center;
  margin-bottom: 1rem;
}

.toolbar .spacer { flex: 1; }

.loading { color: var(--text-dim); padding: 1rem; }

.error {
  color: var(--danger);
  padding: 1rem;
  background: var(--error-bg);
  border-radius: 6px;
  border: 1px solid var(--error-border);
}

/* login page */
.login-wrap {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
}

.login-card {
  background: var(--bg-elev);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 2rem;
  width: 100%;
  max-width: 340px;
  transition: background 0.2s ease, border-color 0.2s ease;
}

.login-card h1 { margin: 0 0 .25rem 0; font-size: 1.3rem; }
.login-card p { color: var(--text-dim); margin: 0 0 1.5rem 0; font-size: .85rem; }
.login-card input { width: 100%; margin-bottom: .75rem; }
.login-card button { width: 100%; padding: .6rem; }

.feedback-desc {
  max-width: 500px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* modal / toast for reset password plaintext */
.toast {
  position: fixed;
  top: 1rem;
  right: 1rem;
  background: var(--bg-elev);
  border: 1px solid var(--border);
  padding: .75rem 1rem;
  border-radius: 6px;
  max-width: 400px;
  box-shadow: var(--toast-shadow);
  z-index: 100;
}

.toast.success { border-color: var(--success); }
.toast.error { border-color: var(--danger); }

.toast code {
  display: block;
  margin-top: .5rem;
  padding: .5rem;
  background: var(--bg);
  border-radius: 4px;
  font-family: "SF Mono", ui-monospace, monospace;
  font-size: .85rem;
  user-select: all;
}

/* payouts page */
.payout-summary {
  background: var(--bg-elev);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: .6rem .9rem;
  margin-bottom: 1rem;
  font-size: .9rem;
  transition: background 0.2s ease, border-color 0.2s ease;
}

.detail-card {
  margin-top: 1.5rem;
  padding: 1rem 1.25rem;
  background: var(--bg-elev);
  border: 1px solid var(--accent);
  border-radius: 8px;
  transition: background 0.2s ease, border-color 0.2s ease;
}

.detail-card h2 {
  margin: 0 0 .75rem 0;
  font-size: 1rem;
  color: var(--text);
}

.detail-card button {
  margin-top: 1rem;
}

