  // ── Moderation (M99panel1) ────────────────────────────────────────────

  let _modRejectPhotoId = null;

  async function initModeration() {
    const sel = qs("#mod-status");
    if (sel) sel.addEventListener("change", renderModerationQueue);
    renderModerationStats();
    renderModerationQueue();
  }

  async function renderModerationStats() {
    const root = qs("#mod-stats");
    if (!root) return;
    try {
      const s = await api("/admin/api/moderation/stats");
      if (!s) return;
      root.innerHTML = "";
      const pairs = [
        ["Pending", s.pending],
        ["Approved", s.approved],
        ["Rejected", s.rejected],
        ["Auto-approved", s.auto_approved],
        ["Decisions (7d)", s.moderated_this_week],
      ];
      pairs.forEach(([label, value], i) => {
        if (i > 0) root.appendChild(document.createTextNode("  ·  "));
        root.appendChild(el("span", { class: "dim", text: label + ": " }));
        root.appendChild(el("strong", { text: String(value) }));
      });
    } catch (e) {
      root.innerHTML = `<span class='error'>Failed: ${e.message}</span>`;
    }
  }

  async function renderModerationQueue() {
    const root = qs("#mod-queue");
    if (!root) return;
    const status = qs("#mod-status")?.value || "pending";
    root.innerHTML = "<div class='loading'>Loading queue…</div>";
    try {
      const data = await api(
        `/admin/api/moderation/photos?status=${encodeURIComponent(status)}&limit=200`
      );
      if (!data) return;
      root.innerHTML = "";
      if (!data.items || data.items.length === 0) {
        root.appendChild(el("div", { class: "dim", text: `No ${status} photos.` }));
        return;
      }
      const grid = el("div", { class: "mod-grid" });
      data.items.forEach(it => grid.appendChild(_makeModCard(it)));
      root.appendChild(grid);
    } catch (e) {
      root.innerHTML = `<div class='error'>Failed to load queue: ${e.message}</div>`;
    }
  }

  function _makeModCard(it) {
    const card = el("div", { class: "mod-card" });
    card.dataset.photoId = it.photo_id;

    card.appendChild(el("img", {
      class: "thumb",
      src: it.image_url,
      alt: `photo ${it.photo_id}`,
      loading: "lazy",
    }));

    const meta = el("div", { class: "meta" }, [
      el("div", { class: "user", text: it.username || `user#${it.user_id}` }),
    ]);
    const subParts = [it.source];
    if (it.slot) subParts.push(`slot=${it.slot}`);
    if (it.uploaded_at) subParts.push(fmtDate(it.uploaded_at));
    meta.appendChild(el("div", { class: "sub", text: subParts.join(" · ") }));
    meta.appendChild(el("div", { class: "sub", text: `id=${it.photo_id}` }));

    if (it.moderation_status !== "pending") {
      const badgeClass = _modBadgeClass(it.moderation_status);
      meta.appendChild(el("div", { style: "margin-top:.35rem" }, [
        el("span", { class: `badge badge-${badgeClass}`, text: it.moderation_status }),
      ]));
    }
    if (it.rejection_reason) {
      meta.appendChild(el("div", { class: "sub", text: `Reason: ${it.rejection_reason}` }));
    }
    card.appendChild(meta);

    const actions = el("div", { class: "actions" });
    if (it.moderation_status === "pending") {
      actions.appendChild(el("button", {
        class: "primary",
        text: "Approve",
        onclick: () => approveModPhoto(it.photo_id),
      }));
      actions.appendChild(el("button", {
        class: "danger",
        text: "Reject",
        onclick: () => _openRejectModal(it),
      }));
    } else {
      const info = [
        it.moderated_by ? `by ${it.moderated_by}` : null,
        it.moderated_at ? fmtDate(it.moderated_at) : null,
      ].filter(Boolean).join(" · ") || "—";
      actions.appendChild(el("div", { class: "dim", style: "font-size:.72rem", text: info }));
    }
    card.appendChild(actions);

    return card;
  }

  function _modBadgeClass(status) {
    return {
      approved: "resolved",
      auto_approved: "new",
      rejected: "banned",
      pending: "read",
    }[status] || "deleted";
  }

  async function approveModPhoto(photoId) {
    try {
      const body = await api(
        `/admin/api/moderation/photos/${encodeURIComponent(photoId)}/approve`,
        { method: "POST" }
      );
      if (!body) return;
      _dismissModCard(photoId, "approved");
      renderModerationStats();
    } catch (e) {
      toast(`Approve failed: ${e.message}`, "error");
    }
  }

  function _openRejectModal(it) {
    _modRejectPhotoId = it.photo_id;
    const modal = qs("#mod-reject-modal");
    if (!modal) return;
    const targetEl = qs("#mod-reject-target");
    if (targetEl) {
      const slotSuffix = it.slot ? ` · slot=${it.slot}` : "";
      targetEl.textContent = `${it.username || "user#" + it.user_id}${slotSuffix} · id=${it.photo_id}`;
    }
    const reasonEl = qs("#mod-reject-reason");
    if (reasonEl) reasonEl.value = "";
    modal.style.display = "flex";
    setTimeout(() => reasonEl?.focus(), 50);
  }

  function cancelReject() {
    _modRejectPhotoId = null;
    const modal = qs("#mod-reject-modal");
    if (modal) modal.style.display = "none";
  }

  async function confirmReject() {
