// ── Payouts (monthly referrer aggregation) ────────────────────────────

async function initPayouts() {
  const sel = qs("#payouts-month");
  if (!sel) return;
  try {
    const data = await api("/admin/api/referrals/payout-summary/months");
    if (!data) return;
    // Always include current month so the page is useful even with zero
    // events this month.
    const curMonth = new Date().toISOString().slice(0, 7);
    const monthSet = new Set(data.months || []);
    monthSet.add(curMonth);
    sel.innerHTML = "";
    [...monthSet].sort().reverse().forEach(m => {
      sel.appendChild(el("option", { value: m, text: m }));
    });
    sel.value = curMonth;
    sel.addEventListener("change", () => renderPayouts());
    renderPayouts();

