      const body = await api(
        `/admin/api/moderation/photos/${encodeURIComponent(photoId)}/approve`,
        { method: "POST" }
      );
      if (!body) return;
      _dismissModCard(photoId, "approved");
      renderModerationStats();
    } catch (e) {
      toast(`Approve failed: ${e.message}`, "error");
    }
  }

  function _openRejectModal(it) {
    _modRejectPhotoId = it.photo_id;
    const modal = qs("#mod-reject-modal");
    if (!modal) return;
    const targetEl = qs("#mod-reject-target");
    if (targetEl) {
      const slotSuffix = it.slot ? ` · slot=${it.slot}` : "";
      targetEl.textContent = `${it.username || "user#" + it.user_id}${slotSuffix} · id=${it.photo_id}`;
    }
    const reasonEl = qs("#mod-reject-reason");
    if (reasonEl) reasonEl.value = "";
    modal.style.display = "flex";
    setTimeout(() => reasonEl?.focus(), 50);
  }

  function cancelReject() {
    _modRejectPhotoId = null;
    const modal = qs("#mod-reject-modal");
    if (modal) modal.style.display = "none";
  }

  async function confirmReject() {
    if (!_modRejectPhotoId) return;
    const reason = qs("#mod-reject-reason")?.value || "";
    const form = new FormData();
    if (reason.trim()) form.append("rejection_reason", reason.trim());
    try {
      const body = await api(
        `/admin/api/moderation/photos/${encodeURIComponent(_modRejectPhotoId)}/reject`,
        { method: "POST", body: form }
      );
      if (!body) return;
      _dismissModCard(_modRejectPhotoId, "rejected");
      cancelReject();
      renderModerationStats();
    } catch (e) {
      toast(`Reject failed: ${e.message}`, "error");
    }
  }

  function _dismissModCard(photoId, action) {
    document.querySelectorAll(".mod-card").forEach(c => {
      if (c.dataset.photoId === photoId) {
        c.classList.add("dismissed");
        setTimeout(() => c.remove(), 280);
      }
    });
    toast(`Photo ${photoId} ${action}`, "success");
  }

  window.AdminPanel = {
    renderDashboard,
    renderUsers,
    renderFeedback,
    renderReferrals,
    renderLikes,
    renderMatches,
    initPayouts,
    renderPayouts,
    renderPayoutDetails,
    exportPayoutsCSV,
    initModeration,
    renderModerationStats,
    renderModerationQueue,
    approveModPhoto,
    cancelReject,
    confirmReject,
  };
})();

