  function openImpersonateModal(u) {
    // Build modal dynamically so we don't need markup in every users-page
    // variant. Appended to body, removed on close.
    const existing = document.getElementById("imp-modal");
    if (existing) existing.remove();

    const reasonEl = el("textarea", {
      id: "imp-reason",
      rows: "3",
      placeholder: "Reason (optional — saved to impersonation_log for audit)",
    });
    const errEl = el("div", {
      class: "dim",
      style: "color:var(--danger);font-size:.78rem;margin-top:.35rem;min-height:1em",
    });
    const startBtn = el("button", {
      class: "primary",
      text: "Start impersonation",
      onclick: () => _confirmImpersonate(u, reasonEl, startBtn, errEl),
    });
    const modal = el("div", {
      id: "imp-modal",
      class: "modal-backdrop",
    }, [
      el("div", { class: "modal" }, [
        el("h2", { text: `Impersonate ${u.username}` }),
        el("div", {
          class: "dim",
          style: "font-size:.8rem;margin-bottom:.5rem",
          text: `id=${u.id} · 15-min token. Chat/DM endpoints will refuse this token.`,
        }),
        reasonEl,
        errEl,
        el("div", { class: "modal-actions" }, [
          el("button", {
            text: "Cancel",
            onclick: () => { modal.remove(); },
          }),
          startBtn,
        ]),
      ]),
    ]);
    document.body.appendChild(modal);
    setTimeout(() => reasonEl.focus(), 50);
  }

  async function _confirmImpersonate(u, reasonEl, startBtn, errEl) {
    errEl.textContent = "";
    startBtn.disabled = true;
    startBtn.textContent = "Requesting token…";
    const form = new FormData();
    const reason = (reasonEl.value || "").trim();
    if (reason) form.append("reason", reason);
    try {
      const body = await api(
        `/admin/api/users/${u.id}/impersonate`,
        { method: "POST", body: form }
      );
      if (!body) return;
      const params = new URLSearchParams();
      params.set("token", body.access_token);
      params.set("target", body.target_user.username);
      params.set("target_id", String(body.target_user.id));
      params.set("exp", body.expires_at);
      params.set("ttl", String(body.ttl_minutes));
      // Hash fragment keeps the token out of the server access log
      // (browsers don't send #fragments with requests).
      const url = `/admin/impersonate-landing.html#${params.toString()}`;
      window.open(url, "_blank", "noopener");
      document.getElementById("imp-modal")?.remove();
      toast(`Impersonation token issued for ${u.username}`, "success");
    } catch (e) {
      errEl.textContent = e.message;
      startBtn.disabled = false;
      startBtn.textContent = "Start impersonation";
    }
  }

  window.AdminPanel = {
    renderDashboard,
    renderUsers,
    renderFeedback,
    renderReferrals,
    renderLikes,
    renderMatches,
    initPayouts,
    renderPayouts,
    renderPayoutDetails,
    exportPayoutsCSV,
    initModeration,
    renderModerationStats,
    renderModerationQueue,
    approveModPhoto,
    cancelReject,
    confirmReject,
    openImpersonateModal,
  };
})();

