async function renderImpersonationHistory() {
  const root = qs("#imp-history-root");
  if (!root) return;
  const adminFilter = qs("#imp-filter-admin")?.value.trim() || "";
  const targetFilter = qs("#imp-filter-target")?.value.trim() || "";
  root.innerHTML = "<div class='loading'>Loading history…</div>";
  const params = new URLSearchParams();
  if (adminFilter) params.set("admin", adminFilter);
  if (targetFilter) params.set("target", targetFilter);
  params.set("limit", "200");
  try {
    const data = await api(`/admin/api/impersonation/log?${params.toString()}`);
    if (!data) return;
    root.innerHTML = "";
    if (!data.items.length) {
      root.appendChild(el("div", { class: "dim", text: "No impersonation events match." }));
      return;
    }
    const tbl = el("table", {}, [
      el("thead", {}, [el("tr", {}, [
        el("th", { text: "ID" }),
        el("th", { text: "When" }),
        el("th", { text: "Admin" }),
        el("th", { text: "Target" }),
        el("th", { text: "Reason" }),
        el("th", { text: "IP" }),
      ])]),
    ]);
    const tbody = el("tbody");
    data.items.forEach(it => {
      tbody.appendChild(el("tr", {}, [
        el("td", { class: "num mono", text: String(it.id) }),
        el("td", { class: "dim mono", text: fmtDate(it.created_at) }),
        el("td", { text: it.admin_username }),
        el("td", { text: it.target_username }),
        el("td", { class: "dim", text: it.reason || "—" }),
        el("td", { class: "dim mono", text: it.ip_address || "—" }),
      ]));
    });
    tbl.appendChild(tbody);
    root.appendChild(tbl);
    root.appendChild(el("div", { class: "dim", text: `${data.total} total` }));
  } catch (e) {
    root.innerHTML = `<div class='error'>Failed to load: ${e.message}</div>`;
  }
}

