LEADERBOARD_PERIODS = ("all_time", "year", "month")


@router.get("/api/referrals/leaderboard")
async def api_referral_leaderboard(
    period: str = "all_time",
    limit: int = 50,
    _=Depends(require_admin_panel_user),
    db: Session = Depends(get_db),
):
    """All-time or current-period referrer leaderboard — sorted by total_value
    desc with a 1-based rank column. Distinct from the month-scoped Payouts
    surface: this is the running ranking, primary use is recognition /
    top-referrer reporting rather than payout cycles.

    period:
      all_time — no date filter
      year     — current UTC year (strftime %Y)
      month    — current UTC YYYY-MM (strftime %Y-%m)
    """
    if period not in LEADERBOARD_PERIODS:
        raise HTTPException(
            status_code=400,
            detail=f"period must be one of {', '.join(LEADERBOARD_PERIODS)}",
        )
    limit = max(1, min(500, limit))
    now = datetime.utcnow()

    q = db.query(
        ReferrerEvent.referrer_username,
        func.sum(ReferrerEvent.value).label("total_value"),
        func.count(ReferrerEvent.id).label("event_count"),
        func.count(func.distinct(ReferrerEvent.referred_username)).label("unique_referred"),
        func.min(ReferrerEvent.created_at).label("first_event_at"),
        func.max(ReferrerEvent.created_at).label("last_event_at"),
    )
    if period == "year":
        q = q.filter(func.strftime("%Y", ReferrerEvent.created_at) == now.strftime("%Y"))
    elif period == "month":
        q = q.filter(func.strftime("%Y-%m", ReferrerEvent.created_at) == now.strftime("%Y-%m"))
    q = (
        q.group_by(ReferrerEvent.referrer_username)
         .order_by(func.sum(ReferrerEvent.value).desc())
         .limit(limit)
    )
    rows = q.all()

    items = []
    for i, r in enumerate(rows, start=1):
        items.append({
            "rank": i,
            "referrer_username": r.referrer_username,
            "total_value": int(r.total_value or 0),
            "event_count": int(r.event_count or 0),
            "unique_referred": int(r.unique_referred or 0),
            "first_event_at": r.first_event_at.isoformat() + "Z" if r.first_event_at else None,
            "last_event_at": r.last_event_at.isoformat() + "Z" if r.last_event_at else None,
        })
    return {
        "period": period,
        "items": items,
        "total": len(items),
        "grand_total": sum(it["total_value"] for it in items),
        "as_of": now.isoformat() + "Z",
    }


