function _lbPeriodLabel(period) {
  return { all_time: "All time", year: "This year", month: "This month" }[period] || period;
}

async function renderLeaderboard() {
  const root = qs("#lb-root");
  const sumEl = qs("#lb-summary");
  if (!root) return;
  const period = qs("#lb-period")?.value || "all_time";
  root.innerHTML = "<div class='loading'>Loading leaderboard…</div>";
  if (sumEl) sumEl.innerHTML = "";
  try {
    const data = await api(`/admin/api/referrals/leaderboard?period=${encodeURIComponent(period)}&limit=50`);
    if (!data) return;
    if (sumEl) {
      sumEl.appendChild(el("span", { class: "dim", text: "Period: " }));
      sumEl.appendChild(el("strong", { text: _lbPeriodLabel(data.period) }));
      sumEl.appendChild(document.createTextNode("  ·  "));
      sumEl.appendChild(el("span", { class: "dim", text: "Referrers: " }));
      sumEl.appendChild(el("strong", { text: String(data.total) }));
      sumEl.appendChild(document.createTextNode("  ·  "));
      sumEl.appendChild(el("span", { class: "dim", text: "Grand total: " }));
      sumEl.appendChild(el("strong", { text: String(data.grand_total) }));
    }
    root.innerHTML = "";
    if (!data.items || data.items.length === 0) {
      root.appendChild(el("div", { class: "dim", text: "No referral events in this period." }));
      return;
    }
    const tbl = el("table", { class: "leaderboard" }, [
      el("thead", {}, [el("tr", {}, [
        el("th", { text: "Rank" }),
        el("th", { text: "Referrer" }),
        el("th", { text: "Total value" }),
        el("th", { text: "Events" }),
        el("th", { text: "Unique referred" }),
        el("th", { text: "First event" }),
        el("th", { text: "Last event" }),
      ])]),
    ]);
    const tbody = el("tbody");
    data.items.forEach(r => {
      const cls = r.rank <= 3 ? `lb-rank-${r.rank}` : "";
      tbody.appendChild(el("tr", { class: cls }, [
        el("td", { class: "num mono lb-rank-cell", text: _lbRankLabel(r.rank) }),
        el("td", { text: r.referrer_username }),
        el("td", { class: "num mono", text: String(r.total_value) }),
        el("td", { class: "num", text: String(r.event_count) }),
        el("td", { class: "num", text: String(r.unique_referred) }),
        el("td", { class: "dim mono", text: fmtDate(r.first_event_at) }),
        el("td", { class: "dim mono", text: fmtDate(r.last_event_at) }),
      ]));
    });
    tbl.appendChild(tbody);
    root.appendChild(tbl);
  } catch (e) {
    root.innerHTML = `<div class='error'>Failed to load: ${e.message}</div>`;
  }
}

function _lbRankLabel(rank) {
  // Medals for top 3, plain number after that.
  if (rank === 1) return "🥇 1";
  if (rank === 2) return "🥈 2";
  if (rank === 3) return "🥉 3";
  return String(rank);
}

async function exportLeaderboardCSV() {
  const period = qs("#lb-period")?.value || "all_time";
  try {
    const data = await api(`/admin/api/referrals/leaderboard?period=${encodeURIComponent(period)}&limit=500`);
    if (!data) return;
    const header = ["rank", "referrer_username", "total_value", "event_count", "unique_referred", "first_event_at", "last_event_at"];
    const rows = [header, ...data.items.map(r => [
      r.rank, r.referrer_username, r.total_value, r.event_count, r.unique_referred,
      r.first_event_at || "", r.last_event_at || "",
    ])];
    const csv = rows.map(row => row.map(cell => {
      const s = cell == null ? "" : String(cell);
      if (/[",\n\r]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
      return s;
    }).join(",")).join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = el("a", { href: url, download: `leaderboard_${period}.csv` });
    document.body.appendChild(a);
    a.click();
    setTimeout(() => { a.remove(); URL.revokeObjectURL(url); }, 100);
  } catch (e) {
    toast(`CSV export failed: ${e.message}`, "error");
  }
}

